import { authAPI } from "../api/api"

const TGL_FETCHING = "AUTH-TOGGLE_IS_FETCHING"
const UPD_AUTH_USER_INFO = "UPDATE_AUTH_USER_INFO"
const SMT_LOGIN_FORM_DATA = "SMT_LOGIN_FORM_DATA"
const SMT_REG_FORM_DATA = "SMT_REG_FORM_DATA"
const UPD_FORM_DATA = "UPD_FORM_DATA"
const LOGIN_ERROR = "LOGIN_ERROR"
const REGISTR_ERROR = "REGISTR_ERROR"

// const DATABASE = {
//     accounts: [
//         { id: 1, username: 'Keksus', email: 'kek@su.ss', permission: 0, groupId: 1 },
//         { id: 2, username: 'Genius', email: 'opss@sss.ss', permission: 1, groupId: 2 }
//     ]
// }

let initState = {
    isFetching: false,
    isAuth: false,
    info: { id: null, username: null, email: null, permission: null, groupId: null },
    form: {
        errorReg: "",
        errorLogin: "",
        login: "",
        pass: "",
        pass_repeat: "",
        email: ""
    }
}

const authReducer = (state = initState, action) => {
    switch (action.type) {
        case TGL_FETCHING: {
            return {...state, isFetching: action.status }
        }
        case UPD_AUTH_USER_INFO: {
            if (action.data.id) return {...state, info: action.data, isAuth: true  }
            else return state
        }
        case UPD_FORM_DATA: {
            if (state.form[action.data.key] !== undefined) {
                return { ...state, form: { ...state.form, [action.data.key]: action.data.value }}
            } else return state
        }
        case SMT_LOGIN_FORM_DATA: {
            let {login, pass} = state.form
            if (!login || !pass) return {...state, form: { ...state.form, errorLogin: 'Введите логин и пароль!' } }
            else {
                console.log('login');
                doLoginRequest({login: state.form.login, password: state.form.pass})
                return {...state, form: { ...state.form, errorLogin: '' }}
            }
        }
        case SMT_REG_FORM_DATA: {
            let {login, pass, pass_repeat, email} = state
            if (!login || !pass || !pass_repeat || !email) return {...state, errorReg: 'Заполните все поля!' }
            if (pass !== pass_repeat) return {...state, errorReg: 'Пароли не совпадают!' }
            if (login.length < 3) return {...state, errorReg: 'Логин должен содержать больше 3 символов!' }
            if (pass_repeat.length < 8) return {...state, errorReg: 'Пароль должен содержать больше 8 символов!' }
            return console.log('ok');
        }
        case LOGIN_ERROR: {
            return { ...state, errorLogin: action.message }
        }
        default:
            return state
    }
}

const toggleIsFetching = (status = false) => ({type: TGL_FETCHING, status})
const updateAuthUserInfo = (data = {}) => ({type: UPD_AUTH_USER_INFO, data})
const changeFormData = (data = {}) => ({type: UPD_FORM_DATA, data})
const submitFormLogin = () => ({ type: SMT_LOGIN_FORM_DATA })

export const getAuthInfo = () => (dispatch) => {
    dispatch(toggleIsFetching(true))
    return authAPI.me()
        .then(res => {
            if(!res.statusCode) {
                dispatch(updateAuthUserInfo({
                    id: res.data.id,
                    username: res.data.username,
                    mail: res.data.mail,
                    permission: res.data.permission
                })).then(result => { dispatch(toggleIsFetching()) })
            } else dispatch(toggleIsFetching())
        })
}
export const updateFormData = data => dispatch => {
    dispatch(changeFormData(data))
}
export const submitLoginForm = () => dispatch => {
    dispatch(submitFormLogin())
    return 
}
const doLoginRequest = (data) => (dispatch) => {
    console.log(data);
    dispatch(toggleIsFetching(true))
    return authAPI.login(data)
        .then(res => {
            if (!res.statusCode) {
                dispatch(getAuthInfo())
                .then(result => dispatch(toggleIsFetching()))
            }
            else dispatch(toggleIsFetching())
        })
}

export default authReducer