import React from 'react'
import { Link, Redirect } from 'react-router-dom'
import { reduxForm, Field } from 'redux-form'
import Preloader from '../Preloader'
import './Auth.css'

const LoginForm = props => {
    return <form className="auth_login_form" onSubmit={props.handleSubmit}>
        <div>
            {/* <Field  /> */}
            <input className="login" required type="text" placeholder="Логин или почта" value={this.props.form.login} onChange={this.onFormChange} /><br/><br/>
            <input className='pass' required type="password" placeholder="Пароль" value={this.props.form.pass} onChange={this.onFormChange} /><br/>
        </div>
        <div>
            <p>Впервые на сайте?<br/><span onClick={() => this.setState({viewWindow: 'Регистрация'})}>Зарегистрируйся прямо сейчас!</span></p>
        </div>
        <div>
            <input type="submit" value="Войти" onClick={this.doLogin} className="auth_btn" /> <br/>
            <Link to={location => `${location.pathname.replace('/auth','')}`} className="auth_btn">Закрыть</Link>
        </div>
        <p className="auth_error">{this.props.form.errorLogin}</p>
    </form>
}

class Auth extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            viewWindow: 'Авторизация'
        }
    }
    onFormChange = e => {
        this.props.updateFormData({key: e.target.className, value: e.target.value })
    }
    doLogin = (e) => {
        e.preventDefault()
        this.props.submitLoginForm()
        // return console.log(a);
    }
    doReg = e => {
        e.preventDefault()
        let {login, pass, pass_repeat, email} = this.state
        if (!login || !pass || !pass_repeat || !email) return this.setState({
            errorReg: 'Заполните все поля!'
        })
        if (pass !== pass_repeat) return this.setState({
            errorReg: 'Пароли не совпадают!'
        })
        if (login.length < 3) return this.setState({
            errorReg: 'Логин должен содержать больше 3 символов!'
        })
        if (pass_repeat.length < 8) return this.setState({
            errorReg: 'Пароль должен содержать больше 8 символов!'
        })
        return console.log('ok'); 
    }
    render() {
        if (this.props.isAuth) return <Redirect to='/profile' />
        return <div className="auth_overlay">
            <div className="auth_window">
                <header className="auth_header">
                    {this.state.viewWindow}
                </header>
                <div className="content">
                    {
                        this.state.viewWindow === 'Авторизация'
                        ? <form className="auth_login_form">
                            <div>
                                <input className="login" required type="text" placeholder="Логин или почта" value={this.props.form.login} onChange={this.onFormChange} /><br/><br/>
                                <input className='pass' required type="password" placeholder="Пароль" value={this.props.form.pass} onChange={this.onFormChange} /><br/>
                            </div>
                            <div>
                                <p>Впервые на сайте?<br/><span onClick={() => this.setState({viewWindow: 'Регистрация'})}>Зарегистрируйся прямо сейчас!</span></p>
                            </div>
                            <div>
                                <input type="submit" value="Войти" onClick={this.doLogin} className="auth_btn" /> <br/>
                                <Link to={location => `${location.pathname.replace('/auth','')}`} className="auth_btn">Закрыть</Link>
                            </div>
                            <p className="auth_error">{this.props.form.errorLogin}</p>
                        </form>
                        : <form className="auth_reg_form">
                            <div>
                                <input className="login" required type="text" placeholder="Логин" value={this.props.form.login} onChange={this.onFormChange} /><br/>
                                <input className="email" required type="text" placeholder="Почта" value={this.props.form.email} onChange={this.onFormChange} /><br/>
                                <input className="pass" required type="password" placeholder="Пароль" value={this.props.form.pass} onChange={this.onFormChange} /><br/>
                                <input className="pass_repeat" required type="password" placeholder="Повтор пароля" value={this.props.form.pass_repeat} onChange={this.onFormChange} /><br/>
                            </div>
                            <div>
                                <p>Уже есть аккаунт?<br/><span onClick={() => this.setState({viewWindow: 'Авторизация'})}>Перейти к авторизации</span></p>
                            </div>
                            <div>
                                <input type="submit" value="Зарегистрироваться" onClick={this.doReg} className="auth_btn" /> <br/>
                                <Link to={location => `${location.pathname.replace('/auth','')}`} className="auth_btn">Закрыть</Link>
                            </div>
                            <p className="auth_error">{this.props.form.errorReg}</p>
                        </form>
                    }                    
                </div>
                { this.props.isFetching && <Preloader /> }
            </div>
        </div>
    }
}

export default Auth