import { getAuthInfo } from "./auth-reducer"

const UPD_INIT = 'UPDATE_INITIALIZATION'

let initState = {
    initializated: false
}

const appReducer = (state = initState, action) => {
    switch (action.type) {
        case UPD_INIT:
            return {
                ...state,
                initializated: true
            }
        default:
            return state
    }
}

const updateInitialization = () => ({ type: UPD_INIT })

export const initApp = () => dispatch => {
    let promise = dispatch(getAuthInfo())
    Promise.all([promise]).then(() => {
        dispatch(updateInitialization())
    })
}

export default appReducer