let initState = {
    isFetching: false,
    isFetchingTable: false,
    lessonsData: [],
    selectedGroup: {},
    groupsList: []
}

const lessonsReducer = (state = initState, action) => {
    switch (action.type) {
        case UPD_LESSONS_DATA:{
            return { ...state, lessonsData: action.data }
        }
        case TGL_FETCHING: {
            return {...state, isFetching: action.status }
        } 
        case TGL_FETCHING_T: {
            return {...state, isFetchingTable: action.status }
        }            
        case UPD_SLCTD_GROUP: {
            let group = {}
            group = state.groupsList.find(i=>(i.id===Number(action.groupId)||i.title===String(action.groupId)))
            return {...state, selectedGroup: group || state.groupsList[0] }
        }
        case UPD_GROUPS_LIST: {
            return {...state, groupsList: action.data }
        }
        default: {
            return state
        }
    }
}

const updateLessonsData = (data = []) => ({type: UPD_LESSONS_DATA, data})
const toggleIsFetching = (status = false) => ({type: TGL_FETCHING, status})
const toggleIsFetchingTable = (status = false) => ({type: TGL_FETCHING_T, status})
const updateSelectedGroup = (groupId) => ({type: UPD_SLCTD_GROUP, groupId})
const updateGroupsList = (data = []) => ({type: UPD_GROUPS_LIST, data})

