export const getLessons = (groupId) => dispatch => {
    dispatch(toggleIsFetchingTable(true))
    lessonsAPI.get(groupId).then(res => {
        dispatch(updateLessonsData(res.data))
        dispatch(toggleIsFetchingTable())
    })
}
export const changeSelectedGroup = (groupId = 1) => dispatch => {
    dispatch(updateSelectedGroup(groupId))
}
export const getGroups = () => dispatch => {
    dispatch(toggleIsFetching(true))
    return groupsAPI.get().then(res => {
        dispatch(updateGroupsList(res.data))
        dispatch(toggleIsFetching())
    })
}

export default lessonsReducer