const TGL_FETCHING = 'CALLS-TOGGLE_IS_FETCHING'

const DATABASE = {
    groups: [
        { id: 1, title: "ИСП9-8" },
        { id: 2, title: "ИСП9-7" },
        { id: 3, title: "ИСП9-13" }
    ],
    calls: [
        { groupId: 1, timeStart: '9:00:00', timeStop: '9:45:00', numLesson: 1 },
        { groupId: 1, timeStart: '9:55:00', timeStop: '10:40:00', numLesson: 2 },
        { groupId: 1, timeStart: '10:50:00', timeStop: '11:35:00', numLesson: 5 },
        { groupId: 1, timeStart: '11:45:00', timeStop: '12:30:00', numLesson: 3 },
        { groupId: 1, timeStart: '12:40:00', timeStop: '13:25:00', numLesson: 4 },
        { groupId: 2, timeStart: '9:00:00', timeStop: '9:45:00', numLesson: 1 },
        { groupId: 2, timeStart: '9:55:00', timeStop: '10:40:00', numLesson: 3 },
        { groupId: 2, timeStart: '10:55:00', timeStop: '11:40:00', numLesson: 2 }
    ]
}

let initState = {
    isFetching: false,
    selectedGroup: {},
    lessonsData: []
}

const callsReducer = (state = initState, action) => {
    switch (action.type) {
        case TGL_FETCHING: {
            return {...state, isFetching: action.status }
        }
        default:
            return state
    }
}

const toggleIsFetching = (status = false) => ({type: TGL_FETCHING, status})

let callsGet = (groupId) => new Promise((resolve, reject) => {
    setTimeout(()=> {
        resolve(DATABASE.calls.filter(call => call.groupId === groupId))
    }, 1500)
})

export const getCalls = (groupId) => dispatch => {
    dispatch(toggleIsFetching(true))
    // request
    callsGet(groupId).then(res => {
        dispatch(toggleIsFetching())
    })
}

export default callsReducer