import React from 'react'
import { Link, NavLink } from 'react-router-dom';

class Header extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            showAccountMenu: false
        }
    }    
    toggleShowAccountMenu = (e, flag) => {
        flag !== undefined
        ? this.setState({ showAccountMenu: flag })
        : this.setState({ showAccountMenu: !this.state.showAccountMenu })
    }
    render() {
        return <header>
        <div className="logo">KSNet ·<small>chatbot</small></div>
        <div className="tabs">
            <NavLink to="/main" className="navItem">Главная</NavLink> 
            <NavLink to={ this.props.selectedGroup.id ? "/lessons/"+this.props.selectedGroup.title : "/lessons" } className="navItem">Расписание</NavLink>
            <NavLink to={ this.props.selectedGroup.id ? "/calls/"+this.props.selectedGroup.title : "/calls" } className="navItem">Звонки</NavLink>
        </div>
        <div className="right">
            {
                this.props.isAuth
                ? (
                    <div className="account" onMouseLeave={(e) => this.toggleShowAccountMenu(e, false)} onClick={this.toggleShowAccountMenu}>
                        <span>аккаунт</span>
                        {
                            this.state.showAccountMenu
                            && (
                                <div className="account_options">
                                    <Link to={"/profile"}>Профиль</Link>
                                    <Link to={"/settings"}>Настройки</Link>
                                    <Link to={"/logout"}>Выйти</Link>
                                </div>
                            )
                        }                                            
                    </div>
                )
                : (
                    <div>
                        <Link to={location => `${location.pathname === "/" ? "" : location.pathname}/auth`}>Войти или Зарегистрироваться</Link>
                    </div>
                )
            }
        </div>                            
    </header>
    }
}

export default Header