import React from 'react'
import './Calls.css'

class Calls extends React.Component {
    constructor(props) {
        super(props)
        this.handleSelect = this.handleSelect.bind(this)
    }
    handleSelect = e => {
        e.preventDefault()
        this.props.handleSelector(e.target.value)
    }
    render() {
        return <div className="calls">
            <h2>Звонки</h2>
        </div>
    }
}

export default Calls