import React from 'react'
import { connect } from 'react-redux'
import { Link } from 'react-router-dom'
import { compose } from 'redux'
import Lessons from "./Lessons"
import { getLessons, changeSelectedGroup, getGroups } from '../../redux/lessons-reducer'
import Preloader from '../Preloader'

class LessonsContainer extends React.Component {
    test = (mes) => alert(mes ? mes : "no message")
    optionsList = () => {
        return this.props.groupsList.map(group => {
            return <Link to={"/lessons/"+group.title} key={group.id} className="lessons_select_list_item" ><li>{group.title}</li></Link>
        })
    }
    createTableForSelectedGroup = () => {
        let res = [] 
        let maxCount = 0
        this.props.lessonsData && this.props.lessonsData.forEach( item => maxCount = maxCount < item.numLesson ? item.numLesson : maxCount)
        for (let row = 1; row <= maxCount; row++) {
            let item = [<th key={row}>{row}</th>]
            for(let col = 1; col < 7; col++) {
                let a = this.props.lessonsData
                    .filter(lesson => (lesson.day === col && lesson.numLesson === row))
                    .sort((a, b) => a.week > b.week ? 1 : -1)
                item.push(<td data-lesson-day={col} data-lesson-num={row} >
                    {
                        a.length > 0
                        ? (a.length > 1 
                            ? (<span>
                                {`${a[0].subject} (${a[0].cabinet} каб.)`}<small>{` (${a[0].week ? "знам" : "числ"}.)`}</small> <br/>
                                {`${a[1].subject} (${a[1].cabinet} каб.)`}<small>{` (${a[1].week ? "знам" : "числ"}.)`}</small>
                                </span>)
                            : `${a[0].subject} (${a[0].cabinet} каб.)`) // (`${a[0].subject} (${a[0].cabinet} каб.)` + (a.length > 1 ? `(числ.) / ${a[1].subject} (${a[1].cabinet} каб.)(знам.)` : ""))
                        : ''
                    }
                </td>)
            }
            res.push(<tr>                
                {item}
            </tr>)            
        }
        return res
    }
    componentDidMount() {
        this.props.getGroups()
    }
    componentDidUpdate(prevProps, prevState) {
        if (prevProps.selectedGroup !== this.props.selectedGroup) {
            this.props.getLessons(this.props.selectedGroup && this.props.selectedGroup.id)
        }
        if (prevProps.groupsList !== this.props.groupsList || (
            prevProps.location.match.params.group !== this.props.location.match.params.group
            && this.props.location.match.params.group !== 'auth')) {
            this.props.changeSelectedGroup(this.props.location.match.params.group)
        }
    }    
    render(){
        // console.log("lessons_component", this.props)
        return this.props.isFetching
            ? <Preloader />
            : <Lessons 
            selectedGroup={this.props.selectedGroup}
            groupsList={this.props.groupsList}
            optionsList={this.optionsList}
            createTableForSelectedGroup={this.createTableForSelectedGroup}
            isFetchingTable={this.props.isFetchingTable}
        />
    }
}

const mapStateToProps = state => {
    return {
        selectedGroup: state.lessonsPage.selectedGroup,
        lessonsData: state.lessonsPage.lessonsData,
        isFetching: state.lessonsPage.isFetching,
        isFetchingTable: state.lessonsPage.isFetchingTable,
        groupsList: state.lessonsPage.groupsList
    }
}

export default compose(connect(mapStateToProps, {getLessons, getGroups, changeSelectedGroup}))(LessonsContainer)