import './App.css';
import React, { Suspense } from 'react'
import { Redirect, Route, Switch, withRouter } from 'react-router-dom';
import Lessons from './components/Lessons/LessonsContainer'; 
import Preloader from './components/Preloader';
import Header from './components/Header/HeaderContainer';
import Auth from './components/Auth/AuthContainer';
import Calls from './components/Calls/CallsContainer';
import Main from './components/Main/Main';
import { compose } from 'redux';
import { initApp } from './redux/app-reducer'
import { connect } from 'react-redux';
import Profile from './components/Profile/ProfileContainer';

class App extends React.Component {
    componentDidMount() {
        this.props.initApp()
    }
    render () {
        if(!this.props.isInit) return <Preloader />
        return <div className="fixed-overlay">
                    <div className="window">
                        <Header />
                        <Suspense fallback={<Preloader />}>
                            <section>
                                <Switch>
                                    <Redirect exact from="/" to="/main" />
                                    <Redirect exact from="/lessons" to="/lessons/1" />
                                    <Redirect exact from="/calls" to="/calls/1" />
                                    <Redirect exact from="/profile" to={"/profile/"+this.props.userId} />
                                    <Route path="/main" render={()=> <Main />} />
                                    <Route path="/lessons/:group"
                                        render={(location)=> <Lessons location={location} />}
                                    />
                                    <Route path="/calls/:group"
                                        render={(location) => <Calls location={location} />}
                                    />
                                    <Route path="/profile/:id?" render={()=> <Profile />} />
                                    <Route path="/settings">Настройки</Route>
                                    {/* <Redirect from="/logout" to="/main" /> */}
                                </Switch>
                                <Route path={/.*\/auth$/i} render={() => <Auth />} />
                            </section>
                        </Suspense>
                    </div>
                </div>
    }
}

let mapStateToProps = state => {
    return {
        isInit: state.app.initializated,
        userId: state.auth.info.id
    }
}

export default compose(withRouter, connect(mapStateToProps, {initApp}))(App);