import React from 'react'
import Preloader from '../Preloader'
import './Lessons.css'

class Lessons extends React.Component {
    constructor(props) {
        super(props)
        this.handleSelectorListShow = this.handleSelectorListShow.bind(this)
        this.state = {
            isMenuShow: false
        }
    }
    handleSelectorListShow = (e, flag) => {
        flag === undefined
        ? this.setState({ isMenuShow: !this.state.isMenuShow })
        : this.setState({ isMenuShow: flag })
    }
    render() {
        // console.log("lessons", this.props);
        return <div className="lessons">
            <div className="lessons_header">
                <h2>Расписание · <small>{this.props.selectedGroup.title}</small></h2>
                <div className="lessons_selector" onMouseLeave={(e) => this.handleSelectorListShow(e, false)}>
                    <span className="lessons_select_group" onClick={this.handleSelectorListShow}>Выбрать группу</span>
                    {
                        this.state.isMenuShow &&
                        <div className="lessons_select_list">
                            {this.props.optionsList()}
                        </div>
                    }                    
                </div>
            </div>
            <div className="lessons_content">
                {
                    this.props.isFetchingTable
                    ? <Preloader />
                    : <table>
                        <tbody>
                            <tr>
                                <th>№<br/>пары</th>
                                <th>Понедельник</th>
                                <th>Вторник</th>
                                <th>Среда</th>
                                <th>Четверг</th>
                                <th>Пятница</th>
                                <th>Суббота</th>
                            </tr>
                            {this.props.createTableForSelectedGroup()}
                        </tbody>
                    </table>
                }
            </div>
        </div> 
    }
}

export default Lessons